import type * as React from 'react';
import type { ProgressProps } from '../../progress';
import type { SpaceProps } from '../../space';
import type { FileProps, UploadFile, UseFileProps } from '../uploadFile/interface';
export type { UploadPictureFileListProps, UploadSimpleTextFileListProps, UploadTextFileListProps, UploadCardFileListProps, } from './index';
/**
 * 文件列表类型。
 * @public
 */
export type UploadListType = 'text' | 'simple-text' | 'picture' | 'card';
/**
 * 上传文件列表显示配置
 * @public
 * @docgen
 */
export type ShowUploadListInterface = Pick<FileProps, 'showRemoveIcon' | 'showPreviewIcon' | 'showDownloadIcon' | 'showErrorIcon' | 'removeIcon' | 'previewIcon' | 'retryIcon' | 'errorIcon' | 'downloadIcon' | 'showRetryIcon'>;
/**
 * @public
 * 用于自定义列表项，需要返回 `ReactNode`。现在可以使用组合式用法来自定义文件列表
 */
export type UploadItemRender<T = any> = (originNode: React.ReactElement, file: UploadFile, fileList: Array<UploadFile<T>>, actions: {
    download: () => void;
    preview: () => void;
    remove: () => void;
    retry: () => void;
}) => React.ReactNode;
export type SharedUploadListProps<T = unknown> = Omit<UseFileProps, 'file'> & {
    itemRender?: (file: UploadFile<T>) => React.ReactNode;
};
/**
 * 上传进度条样式。可参考 Progress 组件。
 * @public
 */
export type UploadProgressProps = Omit<ProgressProps, 'percent' | 'type'>;
/**
 * 文件列表每一项的数据结构。T 为上传接口 response 的类型
 * @public
 */
/**
 * @public
 * `<UploadTextFileList />`、`<UploadSimpleTextFileList />`、`<UploadCardFileList />`、`<UploadPictureFileList />` 的属性。
 */
export interface UploadListProps<Response = unknown> extends SpaceProps {
    /**
     * 自定义文件渲染
     */
    itemRenderer?: (file: UploadFile<Response>) => React.ReactNode;
}
